graphql.query:
fragment PageCursorFields on IPage {
  hasMore
  nextPage {
    after
    limit
    orderBy {
      field
      order
    }
  }
}

fragment Discount on DefinitionDiscount {
  version
  recordType
  description
  discountCharge
  chargeType
  discountPrice
  type
  amount
  duration
  recurringOffset
  source
  evaluationOrder
}

fragment MemberDiscounts on DefinitionDiscount {
  memberDiscounts {
    ...Discount
  }
}

fragment Charge on DefinitionCharge {
  version
  name
  chargeType
  listPrice
  salesPrice
  description
  chargeType
  __typename
  source
}

fragment Pricing on Product {
  pricing(prgs: $prgs) {
    discounts {
      ...Discount
      ...MemberDiscounts
    }
    charges {
      ...Charge
    }
    listOneOffPrice
    listRecurringPrice
    salesOneOffPrice
    salesRecurringPrice
    totalListOneOffPrice
    totalListRecurringPrice
    totalSalesOneOffPrice
    totalSalesRecurringPrice
    unitListOneOffPrice
    unitListRecurringPrice
    unitSalesOneOffPrice
    unitSalesRecurringPrice
  }
}

fragment AttributeMetadataFields on AttributeMetadata {
  version
  attributes {
    name
    customData {
      key
      value
    }
    defaultValue
    mappedCpField
    readOnly
    values {
      label
      value
    }
  }
}

fragment CommercialProductMetadataFields on CommercialProductMetadata {
  sfId
  name
  attributeMetadata {
    ...AttributeMetadataFields
  }
  variantGenerationMetadata
}

fragment ProductFields on IProduct {
  id
  name
  active
  billingFrequency
  contractTerm
  childProducts {
    associationPoint
    quantity
    externalIds {
      key
      value
    }
    product {
      id
      name
      active
      billingFrequency
      contractTerm
      commercialProductCode
      commercialProductMetadata {
        ...CommercialProductMetadataFields
      }
      customFields {
        key
        value
      }
      description
      effectiveStartDate
      effectiveEndDate
      externalIds {
        key
        value
      }
      masterId
      offerCode
    }
  }
  availableChildProducts {
    associationPoint
    product {
      id
      name
      active
      billingFrequency
      contractTerm
      commercialProductCode
      commercialProductMetadata {
        ...CommercialProductMetadataFields
      }
      customFields {
        key
        value
      }
      description
      effectiveStartDate
      effectiveEndDate
      externalIds {
        key
        value
      }
      masterId
      offerCode
    }
    min
    max
    default
    externalIds {
      key
      value
    }
    productAvailability
    group {
      name
      externalIds {
        key
        value
      }
    }
  }
  commercialProductCode
  commercialProductMetadata {
    ...CommercialProductMetadataFields
  }
  customFields {
    key
    value
  }
  description
  effectiveStartDate
  effectiveEndDate
  externalIds {
    key
    value
  }
  masterId
  offerCode
  specializations {
    id
    name
    commercialProductMetadata {
        ...CommercialProductMetadataFields
    }
    active
    billingFrequency
    contractTerm
    commercialProductCode
    description
    effectiveStartDate
    effectiveEndDate
    masterId
    offerCode
    role(version: "2-0-0")
    type
    ...Pricing
  }
  ...Pricing
  role(version: "2-0-0")
  type
}

fragment AvailableProductFields on AvailableProduct {
  associationPoint
  product {
    ...ProductFields
    childProducts {
      associationPoint
      quantity
      externalIds {
        key
        value
      }
      product {
        ...ProductFields
      }
    }
    availableChildProducts {
      associationPoint
      product {
        ...ProductFields
      }
      min
      max
      default
      externalIds {
        key
        value
      }
      productAvailability
      group {
        name
        externalIds {
          key
          value
        }
      }
    }
  }
  min
  max
  default
  externalIds {
    key
    value
  }
  productAvailability
}

fragment ProductFieldsDeep on IProduct {
  ...ProductFields
  categories {
    ...CategoryFields
  }
  childProducts {
    associationPoint
    quantity
    externalIds {
      key
      value
    }
    product {
      ...ProductFields
    }
  }
  availableChildProducts {
    ...AvailableProductFields
    group {
      name
      externalIds {
        key
        value
      }
      members {
        ...AvailableProductFields
      }
    }
  }
}

fragment CategoryFields on ICategory {
  id
  name
  customFields {
    key
    value
  }
  description
  externalIds {
    key
    value
  }
  subcategorySequence
}

query Products_In_Catalogue($catalogueId: ID!, $page: PageCursorInput, $prgs: [String!]! = []) {
  productsInCatalogue(catalogueId: $catalogueId, page: $page) {
    data {
      ...ProductFieldsDeep
      specializations {
        ...ProductFieldsDeep
      }
    }
    ...PageCursorFields
  }
}
